#include <iostream>
#include <fstream>
#include <string>
#include <cctype>
using namespace std;
int main()
{
    ifstream inFile;
    string filename, word, line, temp;
    int count = 0;
    cout << "Enter the filename: ";
    cin >> filename;
    inFile.open(filename.c_str());
    if (inFile.fail())
    {
        cerr << "Error opening file.\n";
        exit(1);
    }
    cout << "Enter the word to search for: ";
    cin >> word;
    while (getline(inFile, line))
    {
        for (int i = 0; i < line.length(); i++)
        {
            if (isalpha(line[i]))
                temp += tolower(line[i]);
            else
            {
                if (temp == word)
                    count++;
                temp = "";
            }
        }
    }
    inFile.close();
    cout << "The word '" << word << "' occurs " << count << " times in the file.\n";
    return 0;
}
